import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.encoder.Encode;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("userInput");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Fixed Page</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println("<p>" + Encode.forHtml(userInput) + "</p>"); // Encode user input for HTML context
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
